export const GLOSSARY_CATEGORIES = [...new Set(GLOSSARY_TERMS.map(t => t.category))].sort();

export function getTermById(id) {
  return GLOSSARY_TERMS.find(t => t.id === id);
}

export function getTermsByCategory(category) {
  return GLOSSARY_TERMS.filter(t => t.category === category);
}

export function searchTerms(query) {
  const q = query.toLowerCase();
  return GLOSSARY_TERMS.filter(t =>
    t.term.toLowerCase().includes(q) ||
    t.definition.toLowerCase().includes(q) ||
    t.category.toLowerCase().includes(q)
  );
}
